export const getGetInvoiceLogsUrl = (id: number) => {
  return `/api/invoices/${id}/logs`;
};

export const getInvoiceLogs = async (
  id: number,
  options?: RequestInit,
): Promise<InvoiceLog[]> => {
  return customFetch<InvoiceLog[]>(getGetInvoiceLogsUrl(id), {
    ...options,
    method: "GET",
  });
};

export const getGetInvoiceLogsQueryKey = (id: number) => {
  return [`/api/invoices/${id}/logs`] as const;
};

export const getGetInvoiceLogsQueryOptions = <
  TData = Awaited<ReturnType<typeof getInvoiceLogs>>,
  TError = ErrorType<unknown>,
>(
  id: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getInvoiceLogs>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetInvoiceLogsQueryKey(id);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getInvoiceLogs>>> = ({
    signal,
  }) => getInvoiceLogs(id, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getInvoiceLogs>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetInvoiceLogsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getInvoiceLogs>>
>;
export type GetInvoiceLogsQueryError = ErrorType<unknown>;

/**
 * @summary Get processing logs for an invoice
 */

export function useGetInvoiceLogs<
  TData = Awaited<ReturnType<typeof getInvoiceLogs>>,
  TError = ErrorType<unknown>,
>(
  id: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getInvoiceLogs>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetInvoiceLogsQueryOptions(id, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
